return await (async function(eda) {
  const fixtureName = '__codex_example___LIB_Footprint_openInEditor_' + Date.now();
  const footprintCandidates = await eda.lib_Footprint.search('STM32');
  const footprintItem = footprintCandidates?.[0];
  const footprintUuid = footprintItem?.uuid;
  const footprintLibraryUuid = footprintItem?.libraryUuid;
  const currentDocument = await eda.dmt_SelectControl.getCurrentDocumentInfo();
  const splitScreenId = currentDocument?.tabId ? await eda.dmt_EditorControl.getSplitScreenIdByTabId(currentDocument.tabId) : undefined;
  const result = await eda.lib_Footprint.openInEditor(footprintUuid, footprintLibraryUuid, splitScreenId);
  return { fixtureName, result };
})(eda);
